import React, {Component} from 'react';
import moment from 'moment';
import 'moment/locale/it';

import colosseo from './assets/colosseo.png';
import './Location.css';

class Location extends Component {
  componentDidMount() {
    moment.locale('it-IT');
  }

  abstract(text) {
    const words = text.split(' ');
    if (words.length <= 8) return text;
    const abstract = words.splice(0, 8);
    return abstract.join(' ') + '…';
  }

  fromPrevious() {
    if (this.props.location.distance.fromPrevious) {
      return (
        <div className="FromPrevious" title="Distanza dalla tappa precedente"><div className="Wrapper"><div className="Text">{(new Intl.NumberFormat('it-IT').format(Math.round(this.props.location.distance.fromPrevious/1000)))}<br />Km</div></div></div>
      );
    }
    return null;
  }

  link() {
    if (this.props.location.link.length > 0)
      return (<a className="Facebook" href={this.props.location.link} target="_facebook" title="Leggi i dettagli su Facebook">f</a>);
    return null;
  }

  isSelected() {
    if (
      this.props.location
      && this.props.location.id
      && this.props.selectedPin
      && this.props.selectedPin.id
      && this.props.selectedPin.id === this.props.location.id
    ) {
      return "Location Location-Selected";
    }
    return "Location";
  }

  render() {
    return (
      <div className={this.isSelected()} id={this.props.location.id}  onClick={() => this.props.centerMap(this.props.location, this.props.index)}>
        <div className="Info" title="Vedi sulla mappa">
          <h2 ><small>{moment(this.props.location.date).format('HH:mm')}</small> - {this.props.location.place}</h2>
          <p>{this.abstract(this.props.location.description)}</p>
        </div>
        {this.fromPrevious()}
        {this.link()}
        
        <div className="Distance">
          <img src={colosseo} alt="Colosseo"/>Roma {(new Intl.NumberFormat('it-IT').format(Math.round(this.props.location.distance.fromRome / 1000)))}Km
        </div>

        <div className="Hover">
          Vedi sulla Mappa
        </div>

      </div>
    );
  }
}

export default Location;